import React, { useState } from 'react';
import { 
  Box, 
  Typography, 
  Tab, 
  Tabs, 
  Paper, 
  Chip,
  styled, 
  useTheme,
  alpha
} from '@mui/material';
import { 
  Speed, 
  LocalGasStation, 
  Palette, 
  CalendarMonth,
  ElectricCar,
  AvTimer
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import Grid from './utils/CustomGrid';

export type FeatureCategory = 'exterior' | 'interior' | 'comfort' | 'safety' | 'tech';

export interface FeatureType {
  name: string;
  category: FeatureCategory;
}

// Вспомогательная функция для преобразования строки в тип FeatureCategory
export const asFeatureCategory = (category: string): FeatureCategory => {
  if (category === 'exterior' || 
      category === 'interior' || 
      category === 'comfort' || 
      category === 'safety' || 
      category === 'tech') {
    return category;
  }
  // Если передана неправильная категория, возвращаем безопасное значение по умолчанию
  return 'tech';
};

interface SpecificationsProps {
  engine: string;
  power: string;
  acceleration: string;
  maxSpeed: string;
  color: string;
  year: number;
  features: FeatureType[];
}

const SpecCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(3),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  overflow: 'hidden',
}));

const StyledTabs = styled(Tabs)(({ theme }) => ({
  marginBottom: theme.spacing(3),
  '& .MuiTabs-indicator': {
    backgroundColor: theme.palette.primary.main,
    height: 3,
    borderRadius: 3,
  },
  '& .MuiTab-root': {
    textTransform: 'none',
    fontWeight: 600,
    fontSize: '0.9rem',
    minHeight: 40,
    [theme.breakpoints.down('sm')]: {
      padding: '6px 10px',
      minWidth: 'auto',
    },
  },
}));

const SpecItem = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  textAlign: 'center',
  padding: theme.spacing(1.5),
  borderRadius: theme.spacing(2),
  backgroundColor: alpha(theme.palette.primary.main, 0.05),
  transition: 'all 0.3s ease',
  '&:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.1),
    transform: 'translateY(-2px)',
  },
  '& svg': {
    color: theme.palette.primary.main,
    marginBottom: theme.spacing(1),
    fontSize: '2rem',
  },
}));

const FeatureChip = styled(Chip)(({ theme }) => ({
  margin: theme.spacing(0.5),
  fontWeight: 500,
  borderRadius: theme.spacing(1),
  boxShadow: '0 2px 5px rgba(0,0,0,0.05)',
}));

interface TabPanelProps {
  children?: React.ReactNode;
  index: number;
  value: number;
}

function TabPanel(props: TabPanelProps) {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`car-tabpanel-${index}`}
      aria-labelledby={`car-tab-${index}`}
      {...other}
    >
      {value === index && (
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.3 }}
        >
          {children}
        </motion.div>
      )}
    </div>
  );
}

const CarSpecifications: React.FC<SpecificationsProps> = ({
  engine,
  power,
  acceleration,
  maxSpeed,
  color,
  year,
  features
}) => {
  const theme = useTheme();
  const [tabValue, setTabValue] = useState(0);

  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  // Группировка функций по категориям
  const featuresByCategory = {
    exterior: features.filter(f => f.category === 'exterior'),
    interior: features.filter(f => f.category === 'interior'),
    comfort: features.filter(f => f.category === 'comfort'),
    safety: features.filter(f => f.category === 'safety'),
    tech: features.filter(f => f.category === 'tech'),
  };

  return (
    <SpecCard>
      <StyledTabs
        value={tabValue}
        onChange={handleTabChange}
        variant="scrollable"
        scrollButtons="auto"
        aria-label="car specifications tabs"
      >
        <Tab label="Характеристики" id="car-tab-0" aria-controls="car-tabpanel-0" />
        <Tab label="Комплектация" id="car-tab-1" aria-controls="car-tabpanel-1" />
      </StyledTabs>

      <TabPanel value={tabValue} index={0}>
        <Grid container spacing={2}>
          <Grid size={{ xs: 6, sm: 4 }}>
            <SpecItem>
              <LocalGasStation />
              <Typography variant="body2" color="text.secondary">
                Двигатель
              </Typography>
              <Typography variant="body1" fontWeight={600}>
                {engine}
              </Typography>
            </SpecItem>
          </Grid>
          
          <Grid size={{ xs: 6, sm: 4 }}>
            <SpecItem>
              <ElectricCar />
              <Typography variant="body2" color="text.secondary">
                Мощность
              </Typography>
              <Typography variant="body1" fontWeight={600}>
                {power}
              </Typography>
            </SpecItem>
          </Grid>
          
          <Grid size={{ xs: 6, sm: 4 }}>
            <SpecItem>
              <AvTimer />
              <Typography variant="body2" color="text.secondary">
                Разгон до 100 км/ч
              </Typography>
              <Typography variant="body1" fontWeight={600}>
                {acceleration}
              </Typography>
            </SpecItem>
          </Grid>
          
          <Grid size={{ xs: 6, sm: 4 }}>
            <SpecItem>
              <Speed />
              <Typography variant="body2" color="text.secondary">
                Макс. скорость
              </Typography>
              <Typography variant="body1" fontWeight={600}>
                {maxSpeed}
              </Typography>
            </SpecItem>
          </Grid>
          
          <Grid size={{ xs: 6, sm: 4 }}>
            <SpecItem>
              <Palette />
              <Typography variant="body2" color="text.secondary">
                Цвет
              </Typography>
              <Typography variant="body1" fontWeight={600}>
                {color}
              </Typography>
            </SpecItem>
          </Grid>
          
          <Grid size={{ xs: 6, sm: 4 }}>
            <SpecItem>
              <CalendarMonth />
              <Typography variant="body2" color="text.secondary">
                Год выпуска
              </Typography>
              <Typography variant="body1" fontWeight={600}>
                {year}
              </Typography>
            </SpecItem>
          </Grid>
        </Grid>
      </TabPanel>

      <TabPanel value={tabValue} index={1}>
        <Box>
          {Object.keys(featuresByCategory).map((category) => {
            const categoryFeatures = featuresByCategory[category as keyof typeof featuresByCategory];
            if (categoryFeatures.length === 0) return null;
            
            return (
              <Box key={category} sx={{ mb: 3 }}>
                <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
                  {category === 'exterior' && 'Экстерьер'}
                  {category === 'interior' && 'Интерьер'}
                  {category === 'comfort' && 'Комфорт'}
                  {category === 'safety' && 'Безопасность'}
                  {category === 'tech' && 'Технологии'}
                </Typography>
                <Box sx={{ display: 'flex', flexWrap: 'wrap' }}>
                  {categoryFeatures.map((feature, index) => (
                    <FeatureChip 
                      key={index} 
                      label={feature.name} 
                      color={
                        category === 'safety' ? 'error' :
                        category === 'tech' ? 'info' :
                        category === 'comfort' ? 'success' :
                        'default'
                      }
                      variant={category === 'exterior' || category === 'interior' ? 'outlined' : 'filled'}
                    />
                  ))}
                </Box>
              </Box>
            );
          })}
        </Box>
      </TabPanel>
    </SpecCard>
  );
};

export default CarSpecifications;
